class Solution:
    def numberOfGoodPartitions(self, nums: List[int]) -> int:
        from collections import defaultdict

        MOD = 10**9 + 7
        last_occurrence = defaultdict(int)
        for i, num in enumerate(nums):
            last_occurrence[num] = i

        res = 1
        prev = -1
        for i, num in enumerate(nums):
            prev = max(prev, last_occurrence[num])
            if i == prev:
                res = (res * 2) % MOD

        return res
